import { 菩薩坐身, 上臂常勢, 前臂 } from './pusa.js';
import { 寶香爐 } from '../bujian/sanmaya.js';
import { 臂釧, 腕釧 } from '../bujian/index.js';
export const 金剛香 = (bi) => 菩薩坐身(bi, {
    髻: '天髻',
    冠: '無',
    嚴先: true,
    臂(bi, 筆) {
        const { M, Qk, S, 骨, 衣, 細, 陰, 陽 } = 筆;
        骨(() => { 上臂常勢(筆, -1, 40.0); 上臂常勢(筆, 1, 40.0); });
        骨(() => 陽(() => 前臂(bi, 筆, [-13.7, 40.1], [-6.2, 40.8], { 寬根: 2.5, 寬梢: 1.9, 弓: 0.4, 肘帽: true })));
        骨(() => 陰(() => 前臂(bi, 筆, [13.7, 40.1], [6.2, 40.8], { 寬根: 2.5, 寬梢: 1.9, 弓: -0.4, 肘帽: true })));
        // 爐先落於胸前
        寶香爐(bi, 0, 37.2, 0.85);
        // 兩掌自側捧爐（仰掌相向，指梢承爐腹）
        衣(() => {
            for (const d of [-1, 1]) {
                M(d * 5.8, 40.0);
                Qk(d * 4.3, 40.9, d * 2.7, 40.3);
                S();
                M(d * 5.5, 40.7);
                Qk(d * 4.3, 41.4, d * 3.1, 40.9);
                S();
                細(() => {
                    for (const t of [0, 1, 2]) {
                        M(d * (5.4 - t * 1.0), 39.75 - t * 0.12);
                        Qk(d * (5.1 - t * 1.0), 39.4 - t * 0.12, d * (4.7 - t * 1.0), 39.25 - t * 0.12);
                        S();
                    }
                });
            }
        });
        // 嚴
        臂釧(bi, -1, 12.1, 14.5, 33.4);
        臂釧(bi, 1, 12.1, 14.5, 33.4);
        細(() => {
            腕釧(bi, [[-7.2, 39.5, -6.5, 40.4, -7.2, 41.5], [-6.3, 39.3, -5.6, 40.2, -6.3, 41.3]], [-6.5, 40.3]);
            腕釧(bi, [[7.2, 39.5, 6.5, 40.4, 7.2, 41.5], [6.3, 39.3, 5.6, 40.2, 6.3, 41.3]], [6.5, 40.3]);
        });
    },
});
